package integration

import (
	"bytes"
	"context"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"testing"

	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/protobuf/encoding/protojson"
)

// MockStorer implements the evaluation.Storer interface for testing
type MockStorer struct {
	flags         map[string]*flipt.Flag
	rules         map[string][]*storage.EvaluationRule
	distributions map[string][]*storage.EvaluationDistribution
	rollouts      map[string][]*storage.EvaluationRollout
}

func (m *MockStorer) GetFlag(ctx context.Context, req storage.ResourceRequest) (*flipt.Flag, error) {
	key := req.Key
	if flag, ok := m.flags[key]; ok {
		return flag, nil
	}
	return nil, ErrFlagNotFound{key: key}
}

func (m *MockStorer) GetEvaluationRules(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRule, error) {
	if rules, ok := m.rules[req.Key]; ok {
		return rules, nil
	}
	return []*storage.EvaluationRule{}, nil
}

func (m *MockStorer) GetEvaluationDistributions(ctx context.Context, req storage.IDRequest) ([]*storage.EvaluationDistribution, error) {
	if dists, ok := m.distributions[req.ID]; ok {
		return dists, nil
	}
	return []*storage.EvaluationDistribution{}, nil
}

func (m *MockStorer) GetEvaluationRollouts(ctx context.Context, req storage.ResourceRequest) ([]*storage.EvaluationRollout, error) {
	if rollouts, ok := m.rollouts[req.Key]; ok {
		return rollouts, nil
	}
	return []*storage.EvaluationRollout{}, nil
}

// ErrFlagNotFound is a simple error implementation for testing
type ErrFlagNotFound struct {
	key string
}

func (e ErrFlagNotFound) Error() string {
	return "flag not found: " + e.key
}

// setupTestServer creates a test evaluation server with mock storage
func setupTestServer() *grpc.Server {
	grpcServer := grpc.NewServer()

	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"enabled_boolean_flag": {
				Key:     "enabled_boolean_flag",
				Name:    "Enabled Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
			"disabled_boolean_flag": {
				Key:     "disabled_boolean_flag",
				Name:    "Disabled Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: false,
			},
			"enabled_variant_flag": {
				Key:     "enabled_variant_flag",
				Name:    "Enabled Variant Flag",
				Type:    flipt.FlagType_VARIANT_FLAG_TYPE,
				Enabled: true,
				Variants: []*flipt.Variant{
					{
						Key:         "variant_a",
						Name:        "Variant A",
						Attachment:  `{"color":"red"}`,
					},
					{
						Key:         "variant_b",
						Name:        "Variant B",
						Attachment:  `{"color":"blue"}`,
					},
				},
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)
	server.RegisterGRPC(grpcServer)

	return grpcServer
}

// TestBooleanEvaluationSuccess tests evaluating an enabled boolean flag
func TestBooleanEvaluationSuccess(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"enabled_boolean_flag": {
				Key:     "enabled_boolean_flag",
				Name:    "Enabled Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-123",
		NamespaceKey: "default",
		FlagKey:      "enabled_boolean_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	resp, err := server.Boolean(context.Background(), req)
	if err != nil {
		t.Fatal("Boolean evaluation failed:", err)
	}

	if !resp.Enabled {
		t.Error("Expected enabled to be true, got false")
	}

	if resp.FlagKey != "enabled_boolean_flag" {
		t.Error("Expected flag_key to be enabled_boolean_flag, got", resp.FlagKey)
	}

	if resp.RequestId != "req-123" {
		t.Error("Expected request_id to match, got", resp.RequestId)
	}
}

// TestBooleanEvaluationDisabledFlag tests evaluating a disabled boolean flag
func TestBooleanEvaluationDisabledFlag(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"disabled_boolean_flag": {
				Key:     "disabled_boolean_flag",
				Name:    "Disabled Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: false,
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-456",
		NamespaceKey: "default",
		FlagKey:      "disabled_boolean_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	resp, err := server.Boolean(context.Background(), req)
	if err != nil {
		t.Fatal("Boolean evaluation failed:", err)
	}

	if resp.Enabled {
		t.Error("Expected enabled to be false for disabled flag, got true")
	}
}

// TestVariantEvaluationSuccess tests evaluating a variant flag
func TestVariantEvaluationSuccess(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"enabled_variant_flag": {
				Key:     "enabled_variant_flag",
				Name:    "Enabled Variant Flag",
				Type:    flipt.FlagType_VARIANT_FLAG_TYPE,
				Enabled: true,
				Variants: []*flipt.Variant{
					{
						Key:        "variant_a",
						Name:       "Variant A",
						Attachment: `{"color":"red"}`,
					},
				},
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-789",
		NamespaceKey: "default",
		FlagKey:      "enabled_variant_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	resp, err := server.Variant(context.Background(), req)
	if err != nil {
		t.Fatal("Variant evaluation failed:", err)
	}

	if resp.FlagKey != "enabled_variant_flag" {
		t.Error("Expected flag_key to be enabled_variant_flag, got", resp.FlagKey)
	}

	if resp.RequestId != "req-789" {
		t.Error("Expected request_id to match, got", resp.RequestId)
	}
}

// TestFlagNotFoundBooleanEvaluation tests evaluating a non-existent flag
func TestFlagNotFoundBooleanEvaluation(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{},
	}

	server := evaluation.New(logger, store)

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-not-found",
		NamespaceKey: "default",
		FlagKey:      "nonexistent_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	_, err := server.Boolean(context.Background(), req)
	if err == nil {
		t.Fatal("Expected error for non-existent flag, got nil")
	}
}

// TestFlagNotFoundVariantEvaluation tests evaluating a non-existent variant flag
func TestFlagNotFoundVariantEvaluation(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{},
	}

	server := evaluation.New(logger, store)

	req := &rpcevaluation.EvaluationRequest{
		RequestId:    "req-variant-not-found",
		NamespaceKey: "default",
		FlagKey:      "nonexistent_variant_flag",
		EntityId:     "user-1",
		Context:      map[string]string{},
	}

	_, err := server.Variant(context.Background(), req)
	if err == nil {
		t.Fatal("Expected error for non-existent variant flag, got nil")
	}
}

// TestBatchEvaluationSuccess tests batch evaluation of multiple flags
func TestBatchEvaluationSuccess(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"boolean_flag": {
				Key:     "boolean_flag",
				Name:    "Boolean Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
			"variant_flag": {
				Key:     "variant_flag",
				Name:    "Variant Flag",
				Type:    flipt.FlagType_VARIANT_FLAG_TYPE,
				Enabled: true,
				Variants: []*flipt.Variant{
					{
						Key:        "variant_a",
						Name:       "Variant A",
						Attachment: `{"color":"red"}`,
					},
				},
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-req-123",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "boolean_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "variant_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
		},
	}

	resp, err := server.Batch(context.Background(), batchReq)
	if err != nil {
		t.Fatal("Batch evaluation failed:", err)
	}

	if len(resp.Responses) != 2 {
		t.Error("Expected 2 responses in batch, got", len(resp.Responses))
	}

	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected first response to be boolean type")
	}

	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected second response to be variant type")
	}
}

// TestBatchEvaluationWithFlagNotFound tests batch evaluation when one flag is not found
func TestBatchEvaluationWithFlagNotFound(t *testing.T) {
	logger, _ := zap.NewDevelopment()

	store := &MockStorer{
		flags: map[string]*flipt.Flag{
			"existing_flag": {
				Key:     "existing_flag",
				Name:    "Existing Flag",
				Type:    flipt.FlagType_BOOLEAN_FLAG_TYPE,
				Enabled: true,
			},
		},
		rollouts: map[string][]*storage.EvaluationRollout{},
	}

	server := evaluation.New(logger, store)

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-req-not-found",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "existing_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "nonexistent_flag",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
		},
	}

	resp, err := server.Batch(context.Background(), batchReq)
	if err != nil {
		t.Fatal("Batch evaluation failed:", err)
	}

	if len(resp.Responses) != 2 {
		t.Error("Expected 2 responses in batch, got", len(resp.Responses))
	}

	// First response should be boolean
	if resp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected first response to be boolean type")
	}

	// Second response should be error (flag not found)
	if resp.Responses[1].Type != rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE {
		t.Error("Expected second response to be error type for missing flag")
	}

	// Verify error details
	errorResp := resp.Responses[1].GetErrorResponse()
	if errorResp == nil {
		t.Fatal("Expected error response, got nil")
	}

	if errorResp.Reason != rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON {
		t.Error("Expected NOT_FOUND error reason")
	}
}

